/**
 * Emit entity deleted event if events are enabled.
 * @internal Used by transaction() for batch deletions.
 */
protected emitEntityDeleted(entity: Entity): void {
  if (this._events) {
    this._events.emit('entityDeleted', {
      entityName: entity.name,
      entity: { ...entity },
    });
  }
}

/**
 * Emit relation deleted event if events are enabled.
 * @internal Used by transaction() for batch deletions.
 */
protected emitRelationDeleted(relation: Relation): void {
  if (this._events) {
    this._events.emit('relationDeleted', {
      relation: { ...relation },
    });
  }
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { GraphStorage } from '../../../src/core/GraphStorage.js';
import { GraphEventEmitter } from '../../../src/core/GraphEventEmitter.js';
import type {
  EntityCreatedEvent,
  EntityUpdatedEvent,
  EntityDeletedEvent,
  GraphLoadedEvent,
} from '../../../src/core/GraphEventEmitter.js';
import { promises as fs } from 'fs';
import { join } from 'path';
import { tmpdir } from 'os';

describe('GraphEventEmitter', () => {
  let emitter: GraphEventEmitter;

  beforeEach(() => {
    emitter = new GraphEventEmitter();
  });

  describe('basic event handling', () => {
    it('should emit and receive events', () => {
      const listener = vi.fn();
      emitter.on('entityCreated', listener);

      emitter.emit('entityCreated', {
        entity: { name: 'Test', entityType: 'test', observations: [] },
      });

      expect(listener).toHaveBeenCalledTimes(1);
      expect(listener.mock.calls[0][0].entity.name).toBe('Test');
    });

    it('should add timestamp to events automatically', () => {
      let receivedEvent: EntityCreatedEvent | null = null;
      emitter.on('entityCreated', (event) => {
        receivedEvent = event;
      });

      const beforeEmit = Date.now();
      emitter.emit('entityCreated', {
        entity: { name: 'Test', entityType: 'test', observations: [] },
      });
      const afterEmit = Date.now();

      expect(receivedEvent?.timestamp).toBeDefined();
      const eventTime = new Date(receivedEvent!.timestamp).getTime();
      expect(eventTime).toBeGreaterThanOrEqual(beforeEmit);
      expect(eventTime).toBeLessThanOrEqual(afterEmit);
    });

    it('should support multiple listeners for same event', () => {
      const listener1 = vi.fn();
      const listener2 = vi.fn();

      emitter.on('entityCreated', listener1);
      emitter.on('entityCreated', listener2);

      emitter.emit('entityCreated', {
        entity: { name: 'Test', entityType: 'test', observations: [] },
      });

      expect(listener1).toHaveBeenCalledTimes(1);
      expect(listener2).toHaveBeenCalledTimes(1);
    });

    it('should remove listeners with off()', () => {
      const listener = vi.fn();
      emitter.on('entityCreated', listener);
      emitter.off('entityCreated', listener);

      emitter.emit('entityCreated', {
        entity: { name: 'Test', entityType: 'test', observations: [] },
      });

      expect(listener).not.toHaveBeenCalled();
    });

    it('should support once() for single-use listeners', () => {
      const listener = vi.fn();
      emitter.once('entityCreated', listener);

      emitter.emit('entityCreated', {
        entity: { name: 'Test1', entityType: 'test', observations: [] },
      });
      emitter.emit('entityCreated', {
        entity: { name: 'Test2', entityType: 'test', observations: [] },
      });

      expect(listener).toHaveBeenCalledTimes(1);
      expect(listener.mock.calls[0][0].entity.name).toBe('Test1');
    });

    it('should return listener count', () => {
      expect(emitter.listenerCount('entityCreated')).toBe(0);

      emitter.on('entityCreated', () => {});
      expect(emitter.listenerCount('entityCreated')).toBe(1);

      emitter.on('entityCreated', () => {});
      expect(emitter.listenerCount('entityCreated')).toBe(2);
    });

    it('should return event names', () => {
      emitter.on('entityCreated', () => {});
      emitter.on('entityDeleted', () => {});

      const names = emitter.eventNames();
      expect(names).toContain('entityCreated');
      expect(names).toContain('entityDeleted');
    });
  });

  describe('event types', () => {
    it('should emit entityUpdated with changes and previousValues', () => {
      let receivedEvent: EntityUpdatedEvent | null = null;
      emitter.on('entityUpdated', (event) => {
        receivedEvent = event;
      });

      emitter.emit('entityUpdated', {
        entity: { name: 'Test', entityType: 'test', observations: [], importance: 5 },
        changes: { importance: 5 },
        previousValues: { importance: 3 },
      });

      expect(receivedEvent?.changes.importance).toBe(5);
      expect(receivedEvent?.previousValues.importance).toBe(3);
    });

    it('should emit graphLoaded with counts', () => {
      let receivedEvent: GraphLoadedEvent | null = null;
      emitter.on('graphLoaded', (event) => {
        receivedEvent = event;
      });

      emitter.emit('graphLoaded', {
        entityCount: 100,
        relationCount: 50,
      });

      expect(receivedEvent?.entityCount).toBe(100);
      expect(receivedEvent?.relationCount).toBe(50);
    });
  });
});

describe('GraphStorage Events Integration', () => {
  let testDir: string;
  let storage: GraphStorage;

  beforeEach(async () => {
    testDir = join(tmpdir(), `event-test-${Date.now()}-${Math.random().toString(36).slice(2)}`);
    await fs.mkdir(testDir, { recursive: true });
    storage = new GraphStorage(join(testDir, 'test.jsonl'));
  });

  afterEach(async () => {
    try {
      await fs.rm(testDir, { recursive: true, force: true });
    } catch {
      // Ignore cleanup errors
    }
  });

  describe('lazy initialization', () => {
    it('should lazily initialize event emitter', () => {
      // Access events property
      const events = storage.events;
      expect(events).toBeInstanceOf(GraphEventEmitter);

      // Same instance on subsequent access
      expect(storage.events).toBe(events);
    });
  });

  describe('entity events', () => {
    it('should emit entityCreated when appending entity', async () => {
      const listener = vi.fn();
      storage.events.on('entityCreated', listener);

      await storage.appendEntity({
        name: 'Test',
        entityType: 'test',
        observations: ['obs1'],
        createdAt: new Date().toISOString(),
        lastModified: new Date().toISOString(),
      });

      expect(listener).toHaveBeenCalledTimes(1);
      expect(listener.mock.calls[0][0].entity.name).toBe('Test');
    });
  });

  describe('graph lifecycle events', () => {
    it('should emit graphSaved after saveGraph', async () => {
      const listener = vi.fn();
      storage.events.on('graphSaved', listener);

      await storage.saveGraph({
        entities: [
          { name: 'E1', entityType: 'test', observations: [] },
          { name: 'E2', entityType: 'test', observations: [] },
        ],
        relations: [
          { from: 'E1', to: 'E2', relationType: 'related' },
        ],
      });

      expect(listener).toHaveBeenCalledTimes(1);
      expect(listener.mock.calls[0][0].entityCount).toBe(2);
      expect(listener.mock.calls[0][0].relationCount).toBe(1);
    });

    it('should emit graphLoaded when loading from disk', async () => {
      // First save some data
      await storage.saveGraph({
        entities: [{ name: 'Test', entityType: 'test', observations: [] }],
        relations: [],
      });

      // Create new storage instance to force load from disk
      const storage2 = new GraphStorage(join(testDir, 'test.jsonl'));
      const listener = vi.fn();
      storage2.events.on('graphLoaded', listener);

      await storage2.loadGraph();

      expect(listener).toHaveBeenCalledTimes(1);
      expect(listener.mock.calls[0][0].entityCount).toBe(1);
    });
  });

  describe('no overhead when unused', () => {
    it('should not emit events when no listeners registered', async () => {
      // Don't access storage.events - this should not cause any overhead
      await storage.saveGraph({
        entities: [{ name: 'Test', entityType: 'test', observations: [] }],
        relations: [],
      });

      // If we get here without errors, the check for _events !== null works
      expect(true).toBe(true);
    });
  });
});

